sql:
SELECT SUM(games_played) AS total_games_played
FROM season_performance
WHERE player_id = '1' AND season = 2022;

SELECT player_id
FROM player_performance
WHERE points_actual = (SELECT MAX(points_actual) FROM player_performance);

external_knowledge:
- 'MVP Candidates' refers to players with a high total points scored; 
- 'not injured' refers to players with an injury status not equal to 'injured reserve'; 
- 'high variation in their expected performance' refers to a standard deviation of projected points greater than 5.
